const userMessage = $input.first().json.chatInput;
const sessionId = $input.first().json.sessionId || 'default-session';

return [{
  json: {
    sessionId,
    userMessage
  }
}];

// --- 1. Parser la sortie du LLM Extract ---
const llmOutput = $input.first().json;

let extracted = null;

// Cas 1 : le Basic LLM Chain retourne directement un objet JSON (quand format:json activé côté Ollama)
if (llmOutput && typeof llmOutput === 'object' && llmOutput.invoice_id !== undefined) {
  extracted = llmOutput;
}
// Cas 2 : le Basic LLM Chain retourne { text: "..." }
else if (llmOutput && typeof llmOutput.text === 'string') {
  try {
    let raw = llmOutput.text.trim();
    raw = raw.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').replace(/^```\s*/i, '');
    const firstBrace = raw.indexOf('{');
    const lastBrace = raw.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1) {
      raw = raw.substring(firstBrace, lastBrace + 1);
    }
    extracted = JSON.parse(raw);
  } catch (err) {
    extracted = { confidence: 0, needs_review: true, _parse_error: err.message };
  }
}

// Fallback si rien n'est exploitable
if (!extracted) {
  extracted = { confidence: 0, needs_review: true };
}

// --- 2. Récupérer le draft depuis PG Load Session et le userMessage ---
const pgSession = $('Merge Session').first().json.session;
const loadState = $('Load Session State').first().json;

const sessionId = pgSession.session_id;
const turn = pgSession.turn;
const draft = JSON.parse(JSON.stringify(pgSession.draft));

// Garantir la structure minimale du draft (si Postgres retourne un truc partiel)
draft.customer = draft.customer || {};
draft.product = draft.product || {};
draft.invoice = draft.invoice || {};
draft.issue = draft.issue || {};
draft.history = draft.history || [];
draft.missing_fields = draft.missing_fields || [];
draft.warnings = draft.warnings || [];
draft.status = draft.status || "draft";

// --- 2b. Guardrail: if advisor was answering a direct question, force new_sav
//     regardless of LLM classification. This prevents domain-knowledge overrides.
const lastAskedField = pgSession.draft?.last_asked_field;
if (lastAskedField && (!extracted.intent || extracted.intent === 'other')) {
  const reply = (loadState.userMessage || '').trim();
  extracted.intent = 'new_sav';
  if (reply) {
    const p = lastAskedField.path;
    if (p.startsWith('product'))        extracted.product_type      = extracted.product_type      || reply;
    else if (p === 'issue.type')         extracted.issue_type        = extracted.issue_type        || reply;
    else if (p === 'issue.description')  extracted.issue_description = extracted.issue_description || reply;
    else if (p === 'customer.name')      extracted.customer_name     = extracted.customer_name     || reply;
    else if (p === 'invoice.invoice_number') extracted.invoice_id       = extracted.invoice_id        || reply;
  }
}

// --- 3. Merge non-destructif ---
if (extracted.invoice_id) {
  draft.invoice.invoice_number = String(extracted.invoice_id);
}
if (extracted.product_type) {
  draft.product.category = extracted.product_type;
}
if (extracted.product_brand) {
  draft.product.brand = extracted.product_brand;
}
if (extracted.product_name) {
  draft.product.label = extracted.product_name;
}
if (extracted.issue_type) {
  draft.issue.type = extracted.issue_type;
}
if (extracted.issue_description) {
  draft.issue.description = extracted.issue_description;
}
if (extracted.customer_name) {
  draft.customer.name = extracted.customer_name;
}
if (extracted.context) {
  draft.issue.context = extracted.context;
}

// --- 4. Sortir le draft fusionné ---
return [{
  json: {
    sessionId,
    userMessage: loadState.userMessage,
    draft,
    extraction: extracted,
    intent: extracted?.intent || 'new_sav',
    turn
  }
}];

