const invoiceNumber = draft.invoice.invoice_number;
const invoice = $input.first().json.data.find((i) => String(i.invoice_number) == String(invoiceNumber));

if (!invoice) {
  draft.warnings = draft.warnings || [];
  draft.warnings.push('Facture ' + invoiceNumber + ' introuvable en base');
  return [{ json: { ...input, draft, invoice_found: false } }];
}

draft.invoice.db_id      = invoice.id;
draft.invoice.date       = invoice.date;
draft.invoice.store      = invoice.store;
draft.invoice.amount_ttc = invoice.amount_ttc;

if (!draft.customer.id)           draft.customer.id           = invoice.customer?.external_id || null;
if (!draft.customer.name)         draft.customer.name         = invoice.customer?.name || null;
if (!draft.customer.phone)        draft.customer.phone        = invoice.customer?.phone || null;
if (!draft.customer.email)        draft.customer.email        = invoice.customer?.email || null;
if (!draft.customer.loyalty_tier) draft.customer.loyalty_tier = invoice.customer?.loyalty_tier || null;

return [{ json: { ...input, draft, invoice_found: true } }];

