/**
 * Calculate similarity percentage between two strings
 * using Levenshtein Distance
 */
function similarity(str1, str2) {
  // Normalize strings
  const s1 = str1.toLowerCase().trim();
  const s2 = str2.toLowerCase().trim();

  // Early return
  if (s1 === s2) return 100;

  const longer = s1.length > s2.length ? s1 : s2;
  const shorter = s1.length > s2.length ? s2 : s1;

  const distance = levenshteinDistance(longer, shorter);

  return Number(
    (((longer.length - distance) / longer.length) * 100).toFixed(2)
  );
}

function levenshteinDistance(a, b) {
  const matrix = [];

  // Initialize first row/column
  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }

  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }

  // Fill matrix
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1, // substitution
          matrix[i][j - 1] + 1,     // insertion
          matrix[i - 1][j] + 1      // deletion
        );
      }
    }
  }

  return matrix[b.length][a.length];
}

const input = $input.all().map((i) => i.json);
const draft = $('Get Invoice').first().json.draft;
const invoice = $('Get Invoice').first().json.data.find((i) => i.invoice_number == draft.invoice.invoice_number);
const userMessage = $('Load Session State').first().json.userMessage

// Auto-assign SKU when invoice has exactly one product
let product;
if (!draft.product.sku && input.length === 1) {
  draft.product.sku = input[0].sku;
  product = input[0];
} else {
  const sku = draft.product.sku;
  product = sku ? input.find((i) => i.sku == sku) : null;
  const results = input.map(product => ({
    product,
    similarity: similarity($('Merge Draft').first().json.extraction.product_name || userMessage, product.label)
  }));

  results.sort((a, b) => b.similarity - a.similarity);

  if (results && results.at(0).similarity > 50) product = results.at(0).product;
}

if (product) {
  // Calcul warranty
  if (invoice && product.warranty_months) {
    const purchaseDate = new Date(invoice.date);
    const warrantyEnd = new Date(purchaseDate);
    warrantyEnd.setMonth(warrantyEnd.getMonth() + product.warranty_months);
    draft.invoice.warranty_end = warrantyEnd.toISOString().split('T')[0];
    draft.invoice.under_warranty = new Date() < warrantyEnd;
  }

  const advisorOverrides = Object.fromEntries(
    Object.entries(draft.product).filter(([, v]) => v != null)
  );

  draft.product = {
    ...product,
    ...advisorOverrides,
    sku: product.sku
  };
}

return [{
  json: {
    invoice_products: input,
    draft,
    product_found: !!product
  }
}];

// Mock DB historique SAV
const historyDB = {
  "C-987": [
    {
      sav_id: "SAV-2024-0455",
      date: "2024-06-10",
      issue: "bruit tambour",
      status: "clos",
      product_sku: "LL-BOSCH-WAG28400"
    }
  ],
  "C-456": []
};

const input = $input.first().json;
const draft = JSON.parse(JSON.stringify(input.draft));
const customerId = draft.customer.id;
const history = customerId ? (historyDB[customerId] || []) : [];

draft.history = history;

return [{
  json: {
    ...input,
    draft,
    history_count: history.length
  }
}];

const input = $input.first().json;
const draft = JSON.parse(JSON.stringify(input.draft));

// --- Champs obligatoires pour pouvoir créer le dossier SAV ---
// askable = true → peut être demandé au conseiller directement
// askable = false → se remplit automatiquement via les mocks quand la facture est trouvée
const required = [
      {
        path: "invoice.invoice_number",
        label: "numéro de facture",
        askable: true,
      },
      { path: "product.sku", label: "produit", askable: true },
      { path: "issue.type", label: "type de panne", askable: true },
      {
        path: "issue.description",
        label: "description du problème",
        askable: true,
      },
      { path: "customer.name", label: "nom du client", askable: true },
      { path: "invoice.date", label: "date d'achat", askable: false },
      { path: "customer.id", label: "identifiant client", askable: false },
    ];

const getByPath = (obj, path) => path.split('.').reduce((o, k) => (o === undefined || o === null) ? undefined : o[k], obj);

const missing = required
  .filter(f => {
    const v = getByPath(draft, f.path);
    return v === undefined || v === null || v === "";
  })
  .map(f => ({ path: f.path, label: f.label, askable: f.askable }));

// --- Contrôles de cohérence (warnings non bloquants) ---
const warnings = new Set(
  Array.isArray(draft.warnings) ? draft.warnings : []
);

// 1. Date achat dans le futur
if (draft.invoice?.date) {
  const purchaseDate = new Date(draft.invoice.date);
  if (purchaseDate > new Date()) {
    warnings.add("Date d'achat incohérente (dans le futur)");
  }
}

// 2. Hors garantie
if (draft.invoice?.under_warranty === false && draft.invoice?.warranty_end) {
  warnings.add(`Produit hors garantie depuis le ${draft.invoice.warranty_end} — prévenir le client des frais potentiels`);
}

// 3. Cohérence panne / produit
const issueProductMatch = {
  "fuite":             ["lave-linge", "lave-vaisselle", "refrigerateur", "chauffe-eau"],
  "ne_demarre_pas":    ["lave-linge", "lave-vaisselle", "refrigerateur", "four", "micro-ondes", "television", "aspirateur"],
  "bruit":             ["lave-linge", "lave-vaisselle", "refrigerateur", "aspirateur", "hotte"],
  "panne_electrique":  ["television", "four", "micro-ondes", "lave-linge", "lave-vaisselle", "refrigerateur", "hotte"],
  "casse":             ["lave-linge", "lave-vaisselle", "refrigerateur", "television", "four", "micro-ondes", "aspirateur", "hotte"]
};

if (draft.issue?.type && draft.product?.category) {
  const validCategories = issueProductMatch[draft.issue.type];
  if (validCategories && !validCategories.includes(draft.product.category)) {
    warnings.add(`Panne "${draft.issue.type}" inhabituelle pour un "${draft.product.category}" — à confirmer avec le conseiller`);
  }
}

// 4. Client avec historique récent (< 6 mois) sur le même produit
if (Array.isArray(draft.history) && draft.history.length > 0 && draft.product?.sku) {
  const sixMonthsAgo = new Date();
  sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);
  const recentSameProduct = draft.history.find(h =>
    h.product_sku === draft.product.sku && new Date(h.date) > sixMonthsAgo
  );
  if (recentSameProduct) {
    warnings.add(`Un SAV récent existe sur ce produit (${recentSameProduct.sav_id} du ${recentSameProduct.date}) — envisager un échange plutôt qu'une réparation`);
  }
}

// --- Mise à jour du draft ---
const isComplete = () => !missing.some(f => f.askable === true);
draft.missing_fields = missing.map(m => m.path);
draft.warnings = [...warnings];
draft.status = isComplete() ? "ready_for_submission" : "draft";

// Option C: store the next field being asked so LLM Extract has context next turn
const nextAskable = missing.find(f => f.askable);
draft.last_asked_field = nextAskable
  ? { path: nextAskable.path, label: nextAskable.label }
  : null;

return [{
  json: {
    sessionId: input.sessionId,
    userMessage: input.userMessage,
    draft,
    missing,
    warnings: [...warnings],
    is_complete: isComplete(),
    turn: input.turn
  }
}];

const input = $input.first().json;
const draft = input.draft || {};

// Garantir la structure
draft.customer = draft.customer || {};
draft.product = draft.product || {};
draft.invoice = draft.invoice || {};
draft.issue = draft.issue || {};
draft.history = draft.history || [];
draft.warnings = draft.warnings || [];

// Champs obligatoires pour créer le ticket
const required = [
  "customer.id",
  "customer.name",
  "product.sku",
  "invoice.invoice_number",
  "invoice.date",
  "issue.type",
  "issue.description"
];

const getByPath = (obj, path) => path.split('.').reduce((o, k) => (o === undefined || o === null) ? undefined : o[k], obj);

const missing = required.filter(path => {
  const v = getByPath(draft, path);
  return v === undefined || v === null || v === "";
});

const isReady = missing.length === 0;

// Générer un ticket_id unique (format SAV-YYYYMMDD-HHMMSS-XXX)
const now = new Date();
const pad = (n, l=2) => String(n).padStart(l, '0');
const folderRef = `SAV-${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}-${pad(Math.floor(Math.random()*1000), 3)}`;

return [{
  json: {
    sessionId: input.sessionId,
    userMessage: input.userMessage,
    draft,
    isReady,
    missing,
    folderRef,
    turn: input.turn
  }
}];

const checkReady = $('Check Ready').first().json;
const createTicket = $('Create SAV Ticket').first().json;

return [{
  json: {
    ticketId: createTicket.folder_reference || checkReady.folderRef,
    createdAt: createTicket.created_at,
    customerName: checkReady.draft?.customer?.name,
    productLabel: checkReady.draft?.product?.label,
    issueType: checkReady.draft?.issue?.type,
    issueDescription: checkReady.draft?.issue?.description,
    warnings: checkReady.draft?.warnings || [],
    underWarranty: checkReady.draft?.invoice?.under_warranty
  }
}];

const getNodeData = (nodeName) => {
  try {
    return $(nodeName).first().json;
  } catch (e) {
    return null;
  }
};

const loadSession = getNodeData('PG Load Session');
const newSession = getNodeData('PG New Session');

const isEmpty = (obj) => !obj || Object.keys(obj).length === 0;

const session = !isEmpty(loadSession) ? loadSession : newSession;

// Increment turn for loaded Sessions
if (!isEmpty(loadSession)) session.turn++;

return [{
  json: {
    session,
    message: $('Load Session State').first().json.userMessage
  }
}];
